  ('judicial-57112235-moex-00678', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲與乙在海產店吃飯時，見乙身上有持有不少現金與貴重珠寶，出於取財意思而將乙打昏，並將乙身上財 物全部搜刮取走花用。甲的行為成立何罪？', '["強盜罪", "搶奪罪", "竊佔罪", "準強盜罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00679', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '廟祝甲告知攤販乙，如果不返還所占用之廟前廣場空地，甲將請雷公擊斃乙，乙因此感到害怕，但仍拒絕 返還。甲成立何罪？', '["甲不成立犯罪", "刑法第305條之恐嚇危害安全罪", "刑法第346條之恐嚇取財罪", "刑法第304條之強制罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00680', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲手持名牌皮包行經路口，乙騎乘機車，自甲後方快速扯走其名牌皮包，揚長而去。甲之刑事責任為何？', '["搶奪罪", "強盜罪", "強制罪", "詐欺罪"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 42, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00681', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '深夜，甲持刀喝令乙女交出錢財，否則將對之不利，乙女驚嚇癱軟在地無法動彈，只能將身上財物全數交 出。關於甲之行為，下列敘述何者正確？', '["成立搶奪罪", "成立強盜取財罪", "成立加重詐欺罪", "成立加重恐嚇取財罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00682', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '工人甲與同事乙發生爭吵，遂於工地以傷害故意追打乙，在追逐過程中，甲把乙打傷倒地，乙頭部因而撞 擊水泥地面而死亡。依實務見解，甲成立何罪？', '["殺人罪", "傷害致死罪", "過失致死罪", "過失傷害致死罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00683', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '關於罪刑法定原則，下列敘述何者錯誤？', '["刑法所規定的犯罪要件與法律效果應力求具體明確", "沒收適用裁判時之法律", "強制工作並非刑罰，故無須受到罪刑法定原則之拘束", "習慣法不得作為論罪科刑之依據"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00684', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲與乙有消費糾紛，乃持槍前往乙宅理論；乙在家中，但拒不出面，甲盛怒之下，朝乙宅開槍掃射，乙當 場死亡。關於甲之行為，下列敘述何者正確？', '["強盜致死罪", "過失致死罪", "普通殺人罪", "義憤殺人罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00685', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '關於過失致死罪之敘述，下列何者正確？', '["我國刑法現有業務過失致死加重處罰之規定", "我國刑法現有重大過失致死加重處罰之規定", "我國刑法現僅有普通過失致死罪之規定", "我國刑法現有輕率過失致死加重處罰之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00686', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲父在乙女小時候，對乙多次為強制性交行為。乙成年後，甲因病陷於無自救能力狀態，乙竟拒絕對甲為 生存所必要之扶助及保護。有關乙之刑責，下列敘述何者正確？', '["乙依據刑法第293條無義務遺棄罪處罰", "乙依據刑法第294條有義務遺棄罪處罰", "乙依據刑法第295條遺棄直系血親尊親屬罪處罰", "乙依據刑法第294條之1不罰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
